@@ -0,0 +1,23 @@
+type Clip = { label: string; startSeconds: number; endSeconds: number };
+
+export function resolveTimelineAssemblerSelectedClip(clips: Clip[], selectedLabel: string) {
+  return clips.find((clip) => clip.label === selectedLabel) ?? clips[0] ?? null;
+}
+
+export function formatClipHeader(clip: Clip) {
+  return `${clip.label} (${clip.startSeconds}-${clip.endSeconds})`;
+}
+
+export function parseRequestQaArgs(args: string[]) {
+  return {
+    path: args[0] ?? null,
+    verbose: args.includes("--verbose"),
+  };
+}
